import { connection } from 'next/server'

async function ServerTimestamp() {
  // Opt out of build-time prerendering so this value is computed per request.
  await connection()

  const timestamp = new Date().toISOString()
  return <time dateTime={timestamp}>{timestamp}</time>
}

export default function Home() {
  return (
    <main>
      <h1>Current server timestamp</h1>
      <p>
        This timestamp is generated on the server for each request:{' '}
        <ServerTimestamp />
      </p>
    </main>
  )
}

